     1→import * as Holidays from 'date-holidays';
     2→import HolidaysType from 'date-holidays';
     3→
     4→const h = new (Holidays as unknown as typeof HolidaysType)('US', { types: ['public'] });
     5→
     6→h.init('US', { types: ['public'] });
     7→
     8→export interface HolidayInfo {
     9→	name: string;
    10→	date: string;
    11→	type: string;
    12→	start: Date;
    13→	end: Date;
    14→}
    15→
    16→export interface HolidayWindow {
    17→	isWithinWindow: boolean;
    18→	daysFromHoliday: number;
    19→	holidayName: string;
    20→	effectMultiplier: number;
    21→}
    22→
    23→export class HolidayHelpers {
    24→	static isUSHoliday(date: Date): boolean {
    25→		const midDayTime = new Date(
    26→			date.getFullYear(),
    27→			date.getMonth(),
    28→			date.getDate(),
    29→			12,
    30→			0,
    31→			0,
    32→		);
    33→		const holiday = h.isHoliday(midDayTime);
    34→		return Boolean(holiday);
    35→	}
    36→	private static readonly HOLIDAY_EFFECT_MULTIPLIERS: Record<string, number> = {
    37→		Christmas: 2.5,
    38→		'Christmas Day': 2.5,
    39→		'Black Friday': 3.0,
    40→		Thanksgiving: 1.8,
    41→		'Thanksgiving Day': 1.8,
    42→		'New Year': 1.5,
    43→		"New Year's Day": 1.5,
    44→		'Independence Day': 1.4,
    45→		'July 4th': 1.4,
    46→		'Memorial Day': 1.3,
    47→		'Labor Day': 1.3,
    48→		"Valentine's Day": 1.6,
    49→		"Mother's Day": 1.4,
    50→		"Father's Day": 1.4,
    51→		Easter: 1.5,
    52→		'Easter Sunday': 1.5,
    53→		'Presidents Day': 1.2,
    54→		"President's Day": 1.2,
    55→		'Martin Luther King Jr. Day': 1.2,
    56→		'Columbus Day': 1.2,
    57→		'Veterans Day': 1.2,
    58→	};
    59→
    60→	static getHolidayInfo(date: Date): HolidayInfo | null {
    61→		try {
    62→			const midDayTime = new Date(
    63→				date.getFullYear(),
    64→				date.getMonth(),
    65→				date.getDate(),
    66→				12,
    67→				0,
    68→				0,
    69→			);
    70→
    71→			const holiday = h.isHoliday(midDayTime);
    72→			if (!holiday) return null;
    73→
    74→			const holidayData = Array.isArray(holiday) ? holiday[0] : holiday;
    75→
    76→			if (!holidayData) return null;
    77→
    78→			return {
    79→				name: holidayData.name,
    80→				date: midDayTime.toISOString().split('T')[0] ?? '',
    81→				type: holidayData.type,
    82→				start: holidayData.start,
    83→				end: holidayData.end,
    84→			};
    85→			// eslint-disable-next-line @typescript-eslint/no-unused-vars
    86→		} catch (error) {
    87→			return null;
    88→		}
    89→	}
    90→
    91→	static getHolidayEffectMultiplier(date: Date): number {
    92→		try {
    93→			const holidayInfo = this.getHolidayInfo(date);
    94→			if (!holidayInfo) return 1.0;
    95→
    96→			for (const [holidayName, multiplier] of Object.entries(
    97→				this.HOLIDAY_EFFECT_MULTIPLIERS,
    98→			)) {
    99→				if (holidayInfo.name.toLowerCase().includes(holidayName.toLowerCase())) {
   100→					return multiplier;
   101→				}
   102→			}
   103→
   104→			return 1.2;
   105→			// eslint-disable-next-line @typescript-eslint/no-unused-vars
   106→		} catch (error) {
   107→			return 1.0;
   108→		}
   109→	}
   110→
   111→	static isWithinHolidayWindow(date: Date, windowDays = 3): HolidayWindow {
   112→		try {
   113→			const result: HolidayWindow = {
   114→				isWithinWindow: false,
   115→				daysFromHoliday: 0,
   116→				holidayName: '',
   117→				effectMultiplier: 1.0,
   118→			};
   119→
   120→			for (let offset = -windowDays; offset <= windowDays; offset++) {
   121→				const checkDate = new Date(date);
   122→				checkDate.setDate(checkDate.getDate() + offset);
   123→
   124→				const holidayInfo = this.getHolidayInfo(checkDate);
   125→				if (holidayInfo) {
   126→					result.isWithinWindow = true;
   127→					result.daysFromHoliday = Math.abs(offset);
   128→					result.holidayName = holidayInfo.name;
   129→					result.effectMultiplier = this.getHolidayEffectMultiplier(checkDate);
   130→
   131→					if (offset === 0 || result.daysFromHoliday === 0) {
   132→						break;
   133→					}
   134→				}
   135→			}
   136→
   137→			return result;
   138→			// eslint-disable-next-line @typescript-eslint/no-unused-vars
   139→		} catch (error) {
   140→			return {
   141→				isWithinWindow: false,
   142→				daysFromHoliday: 0,
   143→				holidayName: '',
   144→				effectMultiplier: 1.0,
   145→			};
   146→		}
   147→	}
   148→
   149→	static getHolidaysForYear(year: number): HolidayInfo[] {
   150→		try {
   151→			const holidays: HolidayInfo[] = [];
   152→			const startDate = new Date(year, 0, 1);
   153→			const endDate = new Date(year, 11, 31);
   154→
   155→			const currentDate = new Date(startDate);
   156→			while (currentDate <= endDate) {
   157→				const holidayInfo = this.getHolidayInfo(currentDate);
   158→				if (holidayInfo) {
   159→					const exists = holidays.some(
   160→						(h) => h.name === holidayInfo.name && h.date === holidayInfo.date,
   161→					);
   162→					if (!exists) {
   163→						holidays.push(holidayInfo);
   164→					}
   165→				}
   166→				currentDate.setDate(currentDate.getDate() + 1);
   167→			}
   168→
   169→			return holidays.sort(
   170→				(a, b) => new Date(a.date).getTime() - new Date(b.date).getTime(),
   171→			);
   172→			// eslint-disable-next-line @typescript-eslint/no-unused-vars
   173→		} catch (error) {
   174→			return [];
   175→		}
   176→	}
   177→
   178→	static getHolidayEffect(date: Date): number {
   179→		const windowInfo = this.isWithinHolidayWindow(date, 3);
   180→
   181→		if (!windowInfo.isWithinWindow) {
   182→			return 1.0;
   183→		}
   184→
   185→		const distanceEffect = Math.max(0, 1 - windowInfo.daysFromHoliday / 3);
   186→		const baseMultiplier = windowInfo.effectMultiplier - 1;
   187→
   188→		return 1.0 + baseMultiplier * distanceEffect;
   189→	}
   190→
   191→	static isBlackFriday(date: Date): boolean {
   192→		try {
   193→			if (isNaN(date.getTime())) {
   194→				return false;
   195→			}
   196→
   197→			const year = date.getFullYear();
   198→
   199→			let firstThursday = 1;
   200→			let safety = 0;
   201→			while (new Date(year, 10, firstThursday).getDay() !== 4 && safety < 7) {
   202→				firstThursday++;
   203→				safety++;
   204→			}
   205→
   206→			if (safety >= 7) {
   207→				return false;
   208→			}
   209→
   210→			const thanksgiving = new Date(year, 10, firstThursday + 21);
   211→			const blackFriday = new Date(thanksgiving);
   212→			blackFriday.setDate(blackFriday.getDate() + 1);
   213→
   214→			return date.toDateString() === blackFriday.toDateString();
   215→		} catch {
   216→			return false;
   217→		}
   218→	}
   219→
   220→	static formatHolidayData(holidays: HolidayInfo[]): {
   221→		date: string;
   222→		effect_window: number;
   223→		impact_multiplier: number;
   224→		name: string;
   225→	}[] {
   226→		return holidays.map((holiday) => {
   227→			try {
   228→				const [year, month, day] = holiday.date.split('-').map(Number);
   229→
   230→				if (!year || !month || !day) {
   231→					throw new Error('Invalid date format');
   232→				}
   233→
   234→				const localDate = new Date(year, month - 1, day, 12, 0, 0);
   235→
   236→				return {
   237→					date: holiday.date,
   238→					effect_window: 6,
   239→					impact_multiplier: this.getHolidayEffectMultiplier(localDate),
   240→					name: holiday.name,
   241→				};
   242→			} catch {
   243→				// Fallback for invalid dates - return default multiplier
   244→				return {
   245→					date: holiday.date,
   246→					effect_window: 6,
   247→					impact_multiplier: 1.0,
   248→					name: holiday.name,
   249→				};
   250→			}
   251→		});
   252→	}
   253→}
   254→
   255→// Backward compatibility export
   256→export const isUSHoliday = (date: Date): boolean => HolidayHelpers.isUSHoliday(date);
