   623→	/**
   624→	 * Calculate cost of a segment based on negative log-likelihood
   625→	 * This method calculates the cost of a segment based on the negative log-likelihood of the data.
   626→	 * Physical meaning: It quantifies how well the segment fits a statistical model, with lower costs indicating better fit.
   627→	 * Based on Killick et al. (2012) "Optimal Detection of Changepoints With a Linear Computational Cost"
   628→	 */
   629→	private static segmentCost(
   630→		values: number[],
   631→		start: number,
   632→		end: number,
   633→		method: string,
   634→	): number {
   635→		const segment = values.slice(start, end + 1);
   636→		const n = segment.length;
   637→		if (n === 0) return Infinity;
   638→		if (n === 1) return 0;
   639→
   640→		const variance = this.variance({ values: segment, precision: null });
   641→
   642→		switch (method) {
   643→			case 'mean':
   644→				return variance === 0 ? 0 : n * Math.log(Math.max(variance, 1e-10));
   645→			case 'variance':
   646→			case 'meanvar':
   647→				return variance === 0
   648→					? 0
   649→					: n * Math.log(Math.max(2 * Math.PI * variance, 1e-10)) + n;
   650→			default:
   651→				throw new Error(`Unknown method: ${method}`);
   652→		}
   653→	}
   654→
   655→	/**
   656→	 * Validate change points using likelihood ratio test
   657→	 * This method checks if the detected change points are statistically significant.
   658→	 * It uses the likelihood ratio test to determine if the change points represent significant shifts in the data.
   659→	 * Physical meaning: It ensures that the detected change points are not due to random fluctuations in the data.
   660→	 * Based on Killick et al. (2012) "Optimal Detection of Changepoints With a Linear Computational Cost"
   661→	 */
   662→	private static validateChangePoints(
   663→		values: number[],
   664→		changePoints: number[],
   665→		significance: number,
   666→		method: string,
   667→	): number[] {
   668→		const validated: number[] = [];
   669→
   670→		for (let i = 0; i < changePoints.length; i++) {
   671→			const cp = changePoints[i];
   672→			if (cp !== undefined) {
   673→				const start = i === 0 ? 0 : (changePoints[i - 1] ?? 0);
   674→				const end =
   675→					i === changePoints.length - 1
   676→						? values.length
   677→						: (changePoints[i + 1] ?? values.length);
   678→
   679→				if (this.isSignificantChangePoint(values, start, cp, end, significance, method)) {
   680→					validated.push(cp);
   681→				}
   682→			}
   683→		}
   684→
   685→		return validated;
   686→	}
   687→
   688→	/**
   689→	 * Test statistical significance using likelihood ratio
   690→	 * This method checks if the change point is statistically significant
   691→	 * by comparing the log-likelihoods of the segments before and after the change point.
   692→	 * Physical meaning: It determines if a change point represents a significant shift in the data distribution.
   693→	 * Based on Killick et al. (2012) "Optimal Detection of Changepoints With a Linear Computational Cost"
   694→	 */
   695→	private static isSignificantChangePoint(
   696→		values: number[],
   697→		start: number,
   698→		cp: number,
   699→		end: number,
   700→		significance: number,
   701→		method: string,
   702→	): boolean {
   703→		const fullSegment = values.slice(start, end);
   704→		const leftSegment = values.slice(start, cp);
   705→		const rightSegment = values.slice(cp, end);
   706→
   707→		if (leftSegment.length < 2 || rightSegment.length < 2) return false;
   708→
   709→		const ll0 = -this.segmentCost(fullSegment, 0, fullSegment.length - 1, method);
   710→		const ll1 =
   711→			-this.segmentCost(leftSegment, 0, leftSegment.length - 1, method) -
   712→			this.segmentCost(rightSegment, 0, rightSegment.length - 1, method);
   713→
   714→		const lrt = 2 * (ll1 - ll0);
   715→
   716→		const df = method === 'meanvar' ? 2 : 1;
   717→
   718→		const criticalValue = this.chiSquareInverse(1 - significance, df);
   719→
   720→		return lrt > criticalValue;
   721→	}
   722→
   723→	/**
   724→	 * Build segments from change points
   725→	 * This method constructs segments based on the detected change points.
   726→	 * Each segment contains the start and end indices, mean, and variance of the values in that segment.
   727→	 * Physical meaning: It provides a structured representation of the data segments between change points.
   728→	 */
   729→	private static buildSegments(
   730→		values: number[],
   731→		changePoints: number[],
   732→	): { start: number; end: number; mean: number; variance: number }[] {
   733→		if (values.length === 0) {
   734→			return [{ start: 0, end: 0, mean: 0, variance: 0 }];
   735→		}
   736→
   737→		const segments: { start: number; end: number; mean: number; variance: number }[] = [];
   738→		const allPoints = [0, ...changePoints, values.length];
   739→
   740→		for (let i = 0; i < allPoints.length - 1; i++) {
   741→			const start = allPoints[i];
   742→			const end = allPoints[i + 1];
   743→			if (start !== undefined && end !== undefined) {
   744→				const segment = values.slice(start, end);
   745→
   746→				segments.push({
   747→					start,
   748→					end: end - 1,
   749→					mean: this.mean({ values: segment, precision: null }),
   750→					variance: this.variance({ values: segment, precision: null }),
   751→				});
   752→			}
   753→		}
   754→
   755→		return segments;
   756→	}
