   758→	/**
   759→	 * Approximation of inverse chi-square CDF
   760→	 * This method approximates the inverse of the chi-square cumulative distribution function.
   761→	 * It is used to determine critical values for statistical tests.
   762→	 * Physical meaning: It provides a way to find the threshold for significance testing in chi-square
   763→	 */
   764→	private static chiSquareInverse(p: number, df: number): number {
   765→		if (p <= 0 || p >= 1) throw new Error('p must be in (0,1)');
   766→		if (df <= 0) throw new Error('df must be positive');
   767→
   768→		// Standard normal quantile (approximation)
   769→		const z = this.normalInverse(p);
   770→
   771→		// Wilson-Hilferty transformation (cspell:ignore Hilferty)
   772→		const h = 2 / (9 * df);
   773→		const term = 1 - h + z * Math.sqrt(h);
   774→
   775→		return df * Math.pow(Math.max(0, term), 3);
   776→	}
   777→
   778→	private static normalInverse(p: number): number {
   779→		if (p <= 0 || p >= 1) throw new Error('p must be in (0,1)');
   780→		if (p === 0.5) return 0;
   781→
   782→		const a: [number, number, number, number, number, number, number] = [
   783→			0, -3.969683028665376e1, 2.209460984245205e2, -2.759285104469687e2,
   784→			1.38357751867269e2, -3.066479806614716e1, 2.506628277459239,
   785→		];
   786→
   787→		const b: [number, number, number, number, number, number] = [
   788→			0, -5.447609879822406e1, 1.615858368580409e2, -1.556989798598866e2,
   789→			6.680131188771972e1, -1.328068155288572e1,
   790→		];
   791→
   792→		const c: [number, number, number, number, number, number, number] = [
   793→			0, -7.784894002430293e-3, -3.223964580411365e-1, -2.400758277161838,
   794→			-2.549732539343734, 4.374664141464968, 2.938163982698783,
   795→		];
   796→
   797→		const d: [number, number, number, number, number] = [
   798→			0, 7.784695709041462e-3, 3.224671290700398e-1, 2.445134137142996, 3.754408661907416,
   799→		];
   800→
   801→		const q = p < 0.5 ? p : 1 - p;
   802→
   803→		let result: number;
   804→
   805→		if (q > 1.28e-3) {
   806→			const t = Math.sqrt(-2 * Math.log(q));
   807→			result =
   808→				(((((c[6] * t + c[5]) * t + c[4]) * t + c[3]) * t + c[2]) * t + c[1]) * t + c[0];
   809→			result /= (((d[4] * t + d[3]) * t + d[2]) * t + d[1]) * t + 1;
   810→		} else {
   811→			const t = q * q;
   812→			result =
   813→				q * (((((a[6] * t + a[5]) * t + a[4]) * t + a[3]) * t + a[2]) * t + a[1]) * t +
   814→				a[0];
   815→			result /= ((((b[5] * t + b[4]) * t + b[3]) * t + b[2]) * t + b[1]) * t + 1;
