    61→export function deepClone<T>(obj: T): T {
    62→	if (obj === null || obj === undefined || typeof obj !== 'object') return obj;
    63→
    64→	const str = JSON.stringify(obj);
    65→	return JSON.parse(str) as T;
    66→}
    67→
    68→export function mergeObjectsDeeply<T extends Record<string, unknown>>(
    69→	target: T,
    70→	source: T,
    71→): T {
    72→	if (!target || typeof target !== 'object') {
    73→		return source;
    74→	}
    75→
    76→	if (!source || typeof source !== 'object') {
    77→		return target;
    78→	}
    79→
    80→	for (const key in source) {
    81→		if (source[key] && typeof source[key] === 'object') {
    82→			target[key] = mergeObjectsDeeply(target[key] || {}, source[key]) as T[Extract<
    83→				keyof T,
    84→				string
    85→			>];
    86→		} else {
    87→			target[key] = source[key];
    88→		}
    89→	}
    90→	return target;
    91→}
    92→
    93→export const requestStore = {
    94→	asyncLocalStorage: new AsyncLocalStorage<RequestStore>(),
    95→
    96→	set<T extends keyof RequestStore>(key: T, value: RequestStore[T]): void {
    97→		const currentStore = this.asyncLocalStorage.getStore();
    98→		if (currentStore) {
