The `EnvConfigService.get` already uses destructuring. For `getEnv`, I need to change from:
```typescript
export const getEnv = <T>(params: { key: string; converter?: (param: unknown) => T }): T => {
  const configService = ...;
  return configService.get<T>(params);
};
```
to:
```typescript
export const getEnv = <T>({ key, converter }: { key: string; converter?: (param: unknown) => T }): T => {
  const configService = ...;
  return configService.get<T>({ key, converter });
};
```

