import { createHash } from 'crypto';

import { STYLES_HASHING_ALGORITHM } from '@constants/common.constant';

const sortKeys = ({ obj }: { obj: unknown }): unknown => {
	if (obj === null) {
		return obj;
	}

	if (typeof obj === 'function') {
		return obj.toString();
	}

	if (typeof obj !== 'object') {
		return obj;
	}

	if (Array.isArray(obj)) {
		return obj.map((item) => sortKeys({ obj: item }));
	}

	const sorted: Record<string, unknown> = {};
	Object.keys(obj as Record<string, unknown>)
		.sort()
		.forEach((key) => {
			sorted[key] = sortKeys({ obj: (obj as Record<string, unknown>)[key] });
		});

	return sorted;
};

export const hashFromObject = ({ obj }: { obj: Record<string, unknown> }): string => {
	const sortedObj = sortKeys({ obj });
	const jsonString = JSON.stringify(sortedObj);
	return createHash(STYLES_HASHING_ALGORITHM).update(jsonString).digest('hex');
};

