   141→			multiplier: HolidayHelpers.getHolidayEffectMultiplier(date),
   142→		};
   143→	}
   144→
   145→	return {
   146→		isHoliday: false,
   147→		holidayName: null,
   148→		multiplier: 1.0,
   149→	};
   150→}
