   152→function addTrend(date: Date, baseValue: number, startYear: number): number {
   153→	const daysSinceStart = Math.floor(
   154→		(date.getTime() - new Date(`${startYear}-01-01`).getTime()) / (1000 * 60 * 60 * 24),
   155→	);
   156→
   157→	// Add some long-term growth trend (2% per year)
   158→	const yearlyGrowth = 1 + (daysSinceStart / 365) * 0.02;
   159→
   160→	// Add some noise/volatility
   161→	const noise = 1 + (Math.random() - 0.5) * 0.3;
   162→
   163→	return baseValue * yearlyGrowth * noise;
   164→}

